int
filewrite(struct file *f, uint64 addr, int n)
{
	struct inode *ip = f->ip;
	if (f->type == FD_INODE) {
		ilock(ip);
		ret = ip->fop->write(ip, 1, addr, f->off, n);
		iunlock(ip);
	}
}

